#!/usr/bin/env python3
"""Validate generated scan reports produced by the report pipeline."""
from pathlib import Path
import json
import sys

root = Path(__file__).resolve().parents[1]
errors = []

# 1. Validate reports/normalized_scan.json
normalized = root / 'reports' / 'normalized_scan.json'
if not normalized.exists():
    errors.append('missing report: reports/normalized_scan.json (run scripts/normalize_nmap_xml.py first)')
else:
    try:
        data = json.loads(normalized.read_text())
        if not isinstance(data.get('target'), str):
            errors.append('reports/normalized_scan.json: missing or invalid "target" field')
        if not isinstance(data.get('ports'), list):
            errors.append('reports/normalized_scan.json: missing or invalid "ports" field')
    except json.JSONDecodeError as exc:
        errors.append(f'reports/normalized_scan.json: invalid JSON ({exc})')

# 2. Validate reports/port_classification.md
classification = root / 'reports' / 'port_classification.md'
if not classification.exists():
    errors.append('missing report: reports/port_classification.md (run scripts/classify_ports.py first)')
else:
    content = classification.read_text()
    if '# Port Classification' not in content:
        errors.append('reports/port_classification.md: missing expected heading "# Port Classification"')
    if '| Protocol' not in content:
        errors.append('reports/port_classification.md: missing expected table header')

# 3. Validate reports/local_scan_report.md
local_report = root / 'reports' / 'local_scan_report.md'
if not local_report.exists():
    errors.append('missing report: reports/local_scan_report.md (run scripts/nmap_xml_to_markdown.py first)')
else:
    content = local_report.read_text()
    if '# Local Scan Report' not in content:
        errors.append('reports/local_scan_report.md: missing expected heading "# Local Scan Report"')
    if '| Protocol' not in content:
        errors.append('reports/local_scan_report.md: missing expected table header')

if errors:
    for error in errors:
        print(error, file=sys.stderr)
    sys.exit(1)
print('OK: report validation passed')

